// ═══════════════════════════════════════
// AGENTE CORRELACIÓN — Detección Cross-Area
// ═══════════════════════════════════════
const input = $('Webhook Correlación').first().json.body || $('Webhook Correlación').first().json;
const anomalies = $('Anomalías Ventana 5min').all().map(i => i.json);
const cooldown = $('Verificar Cooldown').first().json;

const THRESHOLD = 3; // Mínimo áreas para alerta consolidada
const area = input.area || 'unknown';

// Si hay cooldown activo, skip
if (cooldown && cooldown.id) {
  return [{ json: {
    action: 'cooldown_active',
    correlated: false,
    area,
    reason: 'Alerta de correlación reciente, cooldown activo'
  } }];
}

// Agrupar anomalías por área
const areaMap = {};
for (const a of anomalies) {
  if (!areaMap[a.area]) areaMap[a.area] = [];
  areaMap[a.area].push(a);
}

const uniqueAreas = Object.keys(areaMap);
const isCorrelated = uniqueAreas.length >= THRESHOLD;

if (!isCorrelated) {
  return [{ json: {
    action: 'individual_alert',
    correlated: false,
    areas_in_window: uniqueAreas.length,
    threshold: THRESHOLD,
    area
  } }];
}

// ── Inferir causa probable ──
const hour = new Date().getHours();
const isNight = hour >= 22 || hour < 6;
let probableCause = 'anomalia_correlacionada_multiples_areas';

if (uniqueAreas.length >= 6) {
  probableCause = 'posible_falla_suministro_general';
} else if (uniqueAreas.includes('sala_servidores') && isNight) {
  probableCause = 'posible_backup_programado_noches';
} else {
  // Verificar pisos adyacentes
  const floorMap = {
    laboratorio_computo: 2, aulas_teoricas: 1, biblioteca: 3,
    cafeteria: 1, oficinas_admin: 4, sala_servidores: 2,
    estacionamiento: 0, auditorio: 1, gimnasio: 1, laboratorio_quimica: 3
  };
  const floors = [...new Set(uniqueAreas.map(a => floorMap[a]).filter(f => f !== undefined))];
  if (floors.length <= 2) {
    probableCause = `posible_problema_electrico_pisos_${floors.sort().join('_')}`;
  }
}

// Peor severidad
const hasCritical = anomalies.some(a => a.severidad === 'Critico');
const worstSeverity = hasCritical ? 'Critico' : 'Advertencia';

// Preparar detalle de áreas
const areaDetails = uniqueAreas.map(a => {
  const worst = areaMap[a].reduce((w, x) => Number(x.valor_kwh) > Number(w.valor_kwh) ? x : w, areaMap[a][0]);
  return { area: a, kwh: Number(worst.valor_kwh).toFixed(2), severity: worst.severidad };
});

const causeDescriptions = {
  posible_falla_suministro_general: '🔴 Posible falla en suministro eléctrico general',
  posible_backup_programado_noches: '🌙 Posible backup programado nocturno',
  anomalia_correlacionada_multiples_areas: '⚠️ Anomalía simultánea en múltiples áreas'
};

let message = `🔗 <b>ALERTA CORRELACIONADA</b>\n`;
message += `📊 Áreas afectadas: <b>${uniqueAreas.length}</b>\n`;
message += `Causa probable: ${causeDescriptions[probableCause] || probableCause}\n\n`;
areaDetails.forEach(d => {
  message += `  • ${d.area}: ${d.kwh} kWh [${d.severity}]\n`;
});
message += `\n💡 Revisar sistema eléctrico general, no cada área por separado.`;

return [{ json: {
  action: 'consolidated_alert',
  correlated: true,
  areas_affected: uniqueAreas,
  num_areas: uniqueAreas.length,
  probable_cause: probableCause,
  worst_severity: worstSeverity,
  area_details: areaDetails,
  message,
  save_correlation: true,
  timestamp: new Date().toISOString()
} }];

